query:
{
  cloudSqlInstances(
    where: {
      engine: { eq: "postgresql" }
      cloudProvider: { eq: "gcp" }
      OR: [{ dbFlags_NONE: { name: { eq: "cloudsql.enable_pgaudit" } }}, {dbFlags_SOME: {name: { eq: "cloudsql.enable_pgaudit" }, value: { eq: "off" }}}]

    }
  ) {
     ...AssetFragment
  }
}
